+      if (realAudio > 0) {
+        debugPrint('[Player] Audio OK: $realAudio tracks detected');
+        return;
+      }
+
+      // No real audio detected — try ffmpeg proxy
+      debugPrint('[Player] No audio tracks after 3s, trying ffmpeg proxy for $originalUrl');
+      _retryWithProxy(originalUrl);
